module TopModule (
    input wire S,
    input wire R,
    output wire Q,
    output wire Q_bar
);
    reg Q_reg;
    reg Q_bar_reg;

    always @(*) begin
        if (S && !R) begin
            Q_reg = 1;
            Q_bar_reg = 0;
        end else if (!S && R) begin
            Q_reg = 0;
            Q_bar_reg = 1;
        end else if (!S && !R) begin
            Q_reg = Q_reg;
            Q_bar_reg = Q_bar_reg;
        end else begin
            Q_reg = 0;
            Q_bar_reg = 1;
        end
    end

    assign Q = Q_reg;
    assign Q_bar = Q_bar_reg;
endmodule

